pattern.code:
// aq_schema/lib/tools/interfaces/i_tool_handler_registry.dart
abstract interface class IToolHandlerRegistry {
  // Синглтон — инициализируется в приложении
  static IToolHandlerRegistry? _instance;

  static IToolHandlerRegistry get instance {
    assert(_instance != null, 'IToolHandlerRegistry not initialized. '
        'Call IToolHandlerRegistry.initialize() in main().');
    return _instance!;
  }

  static void initialize(IToolHandlerRegistry impl) => _instance = impl;
  static void reset() => _instance = null; // для тестов

  // Контракт — ЧТО нужно, не КАК делать
  void registerHandler(String name, IToolHandler handler);
  Future<ToolOutput> execute(ToolContract contract, ToolInput input);
}

initialization_in_app.code:
// aq_example_app/bin/main.dart — точка сборки
void main() async {
  // Создаём реализации
  final toolRuntime = ToolRuntime(sandboxProvider);

  // Регистрируем синглтоны
  IToolHandlerRegistry.initialize(toolRuntime);
  ISandboxProvider.initialize(sandboxProvider);

  // Теперь любой пакет может использовать:
  // IToolHandlerRegistry.instance.registerHandler(...)
}

example_correct.code:
// ✅ Порт описывает потребность
abstract interface class IToolHandlerRegistry {
  void registerHandler(String name, IToolHandler handler);
  Future<ToolOutput> execute(ToolContract contract, ToolInput input);
  // Не знает о CircuitBreaker, Sandbox, workDir — это детали реализации
}

example_incorrect.code:
// ❌ Порт диктует реализацию
abstract interface class IToolHandlerRegistry {
  void registerHandler(
    String name,
    IToolHandler handler,
    {CircuitBreakerConfig? circuit}  // ❌ Деталь реализации в порту
  );
}

