example.code:
// aq_schema/lib/tools/interfaces/i_tool_handler_registry.dart
abstract interface class IToolHandlerRegistry {
  static IToolHandlerRegistry? _instance;
  static IToolHandlerRegistry get instance {
    assert(_instance != null, 'IToolHandlerRegistry not initialized.');
    return _instance!;
  }
  static void initialize(IToolHandlerRegistry impl) => _instance = impl;
  static void reset() => _instance = null;

  void registerHandler(String name, IToolHandler handler);
  Future<ToolOutput> execute(ToolContract contract, ToolInput input);
}

// aq_tool_runtime/lib/src/tool_runtime.dart
final class ToolRuntime implements IToolHandlerRegistry, IToolRuntimeExecutor {
  @override
  void registerHandler(String name, IToolHandler handler, ...) { ... }
  @override
  Future<ToolOutput> execute(ToolContract contract, ToolInput input) { ... }
}

// aq_mcp/lib/src/client/mcp_registrar.dart
import 'package:aq_schema/tools.dart'; // ✅ Только aq_schema

final class McpRegistrar {
  // Не принимает ToolRuntime — использует порт
  Future<List<String>> register(McpServerConfig config) async {
    // ...
    IToolHandlerRegistry.instance.registerHandler(toolName, handler); // ✅
  }
}

// aq_example_app/bin/main.dart — точка сборки
import 'package:aq_tool_runtime/aq_tool_runtime.dart'; // ✅ Только здесь
import 'package:aq_mcp/aq_mcp.dart';

void main() async {
  final toolRuntime = ToolRuntime(sandboxProvider);
  IToolHandlerRegistry.initialize(toolRuntime); // ✅ Инициализация синглтона

  final registrar = McpRegistrar(); // Не нужен ToolRuntime в конструкторе
  await registrar.register(config);
}

// aq_schema/lib/subject/interfaces/i_subject_session_factory.dart
abstract interface class ISubjectSessionFactory {
  static ISubjectSessionFactory? _instance;
  static ISubjectSessionFactory get instance { ... }
  static void initialize(ISubjectSessionFactory impl) => _instance = impl;
  static void reset() => _instance = null;

  ISubjectSession createSession({
    required SubjectDescriptor descriptor,
    required RunContext context,
    required ISandboxHandle sandbox,
    IToolExecutor? toolExecutor,
  });
}

// aq_subject_runtime — реализует фабрику
final class SubjectSessionFactory implements ISubjectSessionFactory {
  @override
  ISubjectSession createSession({...}) => SubjectSession(...);
}

// aq_subject_registry — использует только порты
final class SubjectRegistryClient implements IAQSubjectRegistry {
  // Не зависит от aq_subject_runtime или aq_sandbox
  @override
  Future<ISubjectSession> createSession(String id, SessionConfig config) async {
    final sandbox = await ISandboxProvider.instance.create(spec);
    final context = await sandbox.createContext(...);
    return ISubjectSessionFactory.instance.createSession(
      descriptor: descriptor,
      context: context,
      sandbox: sandbox,
    );
  }
}

// aq_example_app — точка сборки
void main() async {
  ISandboxProvider.initialize(SandboxProvider('playground'));
  ISubjectSessionFactory.initialize(SubjectSessionFactory());
  IToolHandlerRegistry.initialize(ToolRuntime(ISandboxProvider.instance));
}
